ALTER SESSION SET CONTAINER = XEPDB1;

COMMIT;
SELECT
  w.UWI,
  TO_DATE('2019-06-01','YYYY-MM-DD') AS SAMPLE_DATE,
  ROUND(75 + (MOD(ROWNUM * 7, 17)), 3)       AS METHANE_PCT,
  ROUND(3 + (MOD(ROWNUM * 3, 5)), 3)          AS ETHANE_PCT,
  ROUND(0.8 + (MOD(ROWNUM * 2, 3)), 3)        AS PROPANE_PCT,
  ROUND(0.2 + (MOD(ROWNUM, 2)), 3)            AS BUTANE_PCT,
  ROUND(0.05 + (MOD(ROWNUM, 3) * 0.05), 3)   AS PENTANE_PCT,
  ROUND(0.5 + (MOD(ROWNUM * 4, 4)), 3)        AS CO2_PCT,
  ROUND(0 + (MOD(ROWNUM * 2, 2) * 0.02), 3)  AS H2S_PCT,
  ROUND(1 + (MOD(ROWNUM * 5, 6)), 3)          AS N2_PCT,
  ROUND(950 + (MOD(ROWNUM * 11, 80)), 2)      AS HEATING_VALUE_BTU,
  ROUND(0.58 + (MOD(ROWNUM * 3, 8) * 0.01), 4) AS SPECIFIC_GRAVITY,
  'WELLHEAD'                                   AS SAMPLE_TYPE,
  'LAB-2019-' || ROWNUM                        AS LAB_REFERENCE
FROM welldata.WELL w
ORDER BY w.UWI;

SELECT
  w.UWI,
  TO_DATE('2022-09-01','YYYY-MM-DD') AS SAMPLE_DATE,
  ROUND(76 + (MOD(ROWNUM * 9, 15)), 3)       AS METHANE_PCT,
  ROUND(3.5 + (MOD(ROWNUM * 4, 4)), 3)        AS ETHANE_PCT,
  ROUND(1.0 + (MOD(ROWNUM * 3, 3)), 3)        AS PROPANE_PCT,
  ROUND(0.3 + (MOD(ROWNUM, 2)), 3)            AS BUTANE_PCT,
  ROUND(0.06 + (MOD(ROWNUM, 4) * 0.04), 3)   AS PENTANE_PCT,
  ROUND(0.6 + (MOD(ROWNUM * 5, 5)), 3)        AS CO2_PCT,
  ROUND(0 + (MOD(ROWNUM * 3, 3) * 0.01), 3)  AS H2S_PCT,
  ROUND(1.2 + (MOD(ROWNUM * 6, 5)), 3)        AS N2_PCT,
  ROUND(960 + (MOD(ROWNUM * 13, 70)), 2)      AS HEATING_VALUE_BTU,
  ROUND(0.59 + (MOD(ROWNUM * 4, 7) * 0.01), 4) AS SPECIFIC_GRAVITY,
  'SEPARATOR'                                  AS SAMPLE_TYPE,
  'LAB-2022-' || ROWNUM                        AS LAB_REFERENCE
FROM welldata.WELL w
ORDER BY w.UWI;

COMMIT;
